class Solution(object):
    def countCoprime(self, mat):
        """
        :type mat: List[List[int]]
        :rtype: int
        """
        from math import gcd
        MOD = 10**9 + 7

        m = len(mat)

        # For each row, count occurrences of each value
        # dp[i][g] = ways to choose one element from first i rows with gcd=g
        dp = [0] * 51  # GCD can be at most 150

        # Process first row
        first_row_count = {}
        for val in mat[0]:
            first_row_count[val] = first_row_count.get(val, 0) + 1

        for val, count in first_row_count.items():
            dp[val] = (dp[val] + count) % MOD

        # Process remaining rows
        for row_idx in range(1, m):
            # Count occurrences in current row
            row_count = {}
            for val in mat[row_idx]:
                row_count[val] = row_count.get(val, 0) + 1

            new_dp = [0] * 51

            # For each previous GCD
            for prev_g in range(1, 51):
                if dp[prev_g] == 0:
                    continue

                # For each value in current row
                for curr_val, count in row_count.items():
                    new_g = gcd(prev_g, curr_val)
                    new_dp[new_g] = (new_dp[new_g] + dp[prev_g] * count) % MOD

            dp = new_dp

        return dp[1]
